var selectedExampleId = '';

function cloneEditorConfig(config) {
  return config ? JSON.parse(JSON.stringify(config)) : {};
}

function findEditorExample(id) {
  for (var i = 0; i < EDITOR_EXAMPLES.length; i++) {
    if (EDITOR_EXAMPLES[i].id === id) return EDITOR_EXAMPLES[i];
  }
  return null;
}

function exampleGroups() {
  var groups = [];
  var groupMap = {};
  EDITOR_EXAMPLES.forEach(function(example) {
    var category = example.category || 'Examples';
    if (!groupMap[category]) {
      groupMap[category] = { category: category, examples: [] };
      groups.push(groupMap[category]);
    }
    groupMap[category].examples.push(example);
  });
  return groups;
}

function exampleGlyph(example) {
  var type = example.diagramType || 'Example';
  var glyphs = {
    Flowchart: 'F',
    State: 'S',
    Architecture: 'A',
    Sequence: 'Q',
    Class: 'C',
    ER: 'ER',
    Timeline: 'T',
    Journey: 'J',
    'XY Chart': 'XY',
    Pie: 'P',
    Quadrant: '4Q',
    Gantt: 'G',
  };
  return glyphs[type] || type.slice(0, 2).toUpperCase();
}

function renderExamplePaletteHtml() {
  var examplesHtml = exampleGroups().map(function(group) {
    return '<section class="example-category">'
      + '<div class="example-category-title">' + escHtml(group.category) + '</div>'
      + '<div class="example-category-grid">'
      + group.examples.map(function(example) {
        return '<button class="example-dropdown-item" type="button" role="menuitem" data-example="' + escAttr(example.id) + '" data-diagram="' + escAttr(example.diagramType || '') + '" title="' + escAttr(example.description || example.label) + '">'
          + '<span class="example-item-title"><span class="example-item-glyph" aria-hidden="true">' + escHtml(exampleGlyph(example)) + '</span>' + escHtml(example.label) + '</span>'
          + '<span class="example-item-description">' + escHtml(example.description || '') + '</span>'
          + '</button>';
      }).join('')
      + '</div>'
      + '</section>';
  }).join('');

  return examplesHtml
    + '<div class="example-menu-footer">'
    + '<button class="example-clear-btn" type="button" data-action="clear-editor">New blank diagram</button>'
    + '</div>';
}

function renderExamplePalettes() {
  if (examplesSidebarList) examplesSidebarList.innerHTML = renderExamplePaletteHtml();
}

function markActiveExample(id) {
  selectedExampleId = id || '';
  document.querySelectorAll('.example-dropdown-item').forEach(function(item) {
    item.classList.toggle('active', item.dataset.example === selectedExampleId);
  });
}

function loadEditorExample(id) {
  var example = findEditorExample(id);
  if (!example) return;

  editor.value = example.source.trim();
  state.config = cloneEditorConfig(example.options);
  markActiveExample(example.id);
  if (typeof setEditorErrorLine === 'function') setEditorErrorLine(0);
  if (typeof scheduleDraftSave === 'function') scheduleDraftSave();

  // Examples are source/config presets only; keep the user's selected theme.
  if (typeof applyThemeToPage === 'function') applyThemeToPage(state.theme);
  if (typeof updateThemeButton === 'function') updateThemeButton();

  updateLineNumbers();
  updateCursorPos();
  scheduleRender(0);
  updateHash();
  showToast('Loaded ' + example.label + '.');
}

var examplesSidebar = document.getElementById('examples-sidebar');
var examplesSidebarBtn = document.getElementById('examples-sidebar-btn');
var examplesSidebarClose = document.getElementById('examples-sidebar-close');
var examplesSidebarList = document.getElementById('examples-sidebar-list');

function positionExamplesSidebar() {
  if (!examplesSidebar || !examplesSidebarBtn) return;
  var rect = examplesSidebarBtn.getBoundingClientRect();
  var gutter = 12;
  var preferred = 360;
  var width = Math.min(preferred, window.innerWidth - gutter * 2);
  var left = Math.min(Math.max(gutter, rect.left), window.innerWidth - width - gutter);
  var top = rect.bottom + 8;
  var maxHeight = Math.max(260, window.innerHeight - top - gutter);
  examplesSidebar.style.setProperty('--examples-left', Math.round(left) + 'px');
  examplesSidebar.style.setProperty('--examples-top', Math.round(top) + 'px');
  examplesSidebar.style.setProperty('--examples-width', Math.round(width) + 'px');
  examplesSidebar.style.setProperty('--examples-max-height', Math.round(maxHeight) + 'px');
}

var examplesPopup = typeof createPopupController === 'function' ? createPopupController({
  popup: examplesSidebar,
  trigger: examplesSidebarBtn,
  visibility: { manageTabStops: true, toggleTriggerClass: false },
  beforeOpen: positionExamplesSidebar,
  afterOpen: function(meta) {
    if (examplesSidebarBtn) {
      examplesSidebarBtn.classList.add('active');
      examplesSidebarBtn.setAttribute('aria-pressed', 'true');
    }
    if (meta && meta.focusFirst && examplesSidebarList) {
      var activeItem = examplesSidebarList.querySelector('.example-dropdown-item.active') || examplesSidebarList.querySelector('.example-dropdown-item');
      if (activeItem) activeItem.focus({ preventScroll: false });
    }
  },
  afterClose: function() {
    if (examplesSidebarBtn) {
      examplesSidebarBtn.classList.remove('active');
      examplesSidebarBtn.setAttribute('aria-pressed', 'false');
    }
  },
  contains: function(target) {
    return !!(target.closest('#examples-sidebar') || target.closest('#examples-sidebar-btn'));
  },
  repositionOnResize: true,
  position: positionExamplesSidebar,
}) : { setOpen: function() {} };

function setExamplesSidebarOpen(open, meta) {
  examplesPopup.setOpen(open, meta || {});
}

function openExamplesSidebar() {
  setExamplesSidebarOpen(true, { focusFirst: true });
}

renderExamplePalettes();
setExamplesSidebarOpen(false);

if (examplesSidebarClose) {
  examplesSidebarClose.addEventListener('click', function() {
    setExamplesSidebarOpen(false, { restoreFocus: true });
  });
}

if (examplesSidebarList) {
  examplesSidebarList.addEventListener('click', function(e) {
    var item = e.target.closest('.example-dropdown-item');
    if (!item) return;
    loadEditorExample(item.dataset.example || '');
    setExamplesSidebarOpen(false);
  });
}

document.addEventListener('click', function(e) {
  var starter = e.target.closest('.placeholder-chip[data-example]');
  if (starter) {
    loadEditorExample(starter.dataset.example || '');
    return;
  }
  if (e.target.closest('[data-action="load-example"]')) {
    openExamplesSidebar();
    return;
  }
});


var cfgColors = { bg: '', fg: '', accent: '', line: '', muted: '', surface: '' };
var cfgFont = '';
var cfgPadding = 24;

var COLOR_PRESETS = [
  '#ffffff','#f5f5f5','#e0e0e0','#bdbdbd','#9e9e9e','#757575','#424242','#212121','#000000',
  '#f44336','#e91e63','#ff4081','#ff1744','#d50000',
  '#9c27b0','#673ab7','#3f51b5','#7c4dff','#aa00ff',
  '#2196f3','#03a9f4','#00bcd4','#1565c0','#2979ff','#0091ea',
  '#4caf50','#8bc34a','#009688','#00e676','#1b5e20',
  '#ffeb3b','#ffc107','#ff9800','#ff5722','#ff6d00',
  '#0f1117','#161b22','#1c2128','#0d1117','#1a1a2e','#16213e',
];

function readConfig() {
  var cfg = {};
  if (cfgColors.bg)      cfg.bg      = cfgColors.bg;
  if (cfgColors.fg)      cfg.fg      = cfgColors.fg;
  if (cfgColors.accent)  cfg.accent  = cfgColors.accent;
  if (cfgColors.line)    cfg.line    = cfgColors.line;
  if (cfgColors.muted)   cfg.muted   = cfgColors.muted;
  if (cfgColors.surface) cfg.surface = cfgColors.surface;
  if (cfgFont)           cfg.font    = cfgFont;
  if (cfgPadding !== 24) cfg.padding = cfgPadding;
  state.config = cfg;
  // Per-diagram config rides along in the autosaved draft.
  if (typeof scheduleDraftSave === 'function') scheduleDraftSave();
}

var THEME_COLOR_MAP = { bg: 'bg', fg: 'fg', accent: 'accent', line: 'line', muted: 'muted', surface: 'surface' };

function getThemeColor(key) {
  if (!state.theme || !THEMES[state.theme]) return null;
  return THEMES[state.theme][THEME_COLOR_MAP[key]] || null;
}

function updateColorUI(key) {
  var override = cfgColors[key];
  var themeVal = getThemeColor(key);
  var effective = override || themeVal;
  var label  = document.getElementById('cfg-' + key + '-label');
  var swatch = document.getElementById('cfg-' + key + '-swatch');
  var btn    = document.querySelector('.color-edit-btn[data-cfg="' + key + '"]');

  if (label) {
    label.textContent = override || (themeVal ? themeVal : '–');
    label.style.opacity = override ? '1' : '0.45';
  }
  if (swatch) {
    swatch.style.background = effective || 'transparent';
    swatch.style.border = effective ? '1px solid rgba(0,0,0,0.15)' : '1px dashed var(--fg3)';
    swatch.style.opacity = override ? '1' : (themeVal ? '0.6' : '1');
  }
  if (btn) {
    var labelText = key.charAt(0).toUpperCase() + key.slice(1);
    btn.title = override ? 'Override: ' + override : (themeVal ? 'Theme default: ' + themeVal : 'Not set');
    btn.setAttribute('aria-label', 'Edit ' + labelText + ' color' + (effective ? ': ' + effective : ''));
  }
}

function refreshAllColorUIs() {
  Object.keys(cfgColors).forEach(function(k) { updateColorUI(k); });
}

refreshAllColorUIs();

var cfgEdgeStroke = 1;
var cfgNodeStroke = 1;

function applyStrokeOverrides(svgEl) {
  if (!svgEl) return;
  var defsEl = svgEl.querySelector('defs');

  function inDefs(el) {
    return defsEl && defsEl.contains(el);
  }

  if (cfgEdgeStroke !== 1) {
    var ew = String(cfgEdgeStroke);
    svgEl.querySelectorAll('line, path[fill="none"], polyline[fill="none"]').forEach(function(el) {
      if (!inDefs(el)) el.setAttribute('stroke-width', ew);
    });
    var arrowFactor = Math.sqrt(cfgEdgeStroke);
    svgEl.querySelectorAll('defs marker').forEach(function(marker) {
      var origW = parseFloat(marker.getAttribute('markerWidth')  || '8');
      var origH = parseFloat(marker.getAttribute('markerHeight') || '5');
      marker.setAttribute('viewBox', '0 0 ' + origW + ' ' + origH);
      marker.setAttribute('markerUnits', 'userSpaceOnUse');
      marker.setAttribute('markerWidth',  String(origW * arrowFactor));
      marker.setAttribute('markerHeight', String(origH * arrowFactor));
    });
  }

  if (cfgNodeStroke !== 1) {
    var nw = String(cfgNodeStroke);
    svgEl.querySelectorAll('rect, ellipse, circle, polygon').forEach(function(el) {
      if (!inDefs(el)) el.setAttribute('stroke-width', nw);
    });
  }
}

function makeStrokeSetter(numEl, sliderEl, getVal, setVal) {
  return function(raw) {
    var v = Math.max(0.25, Math.min(6, parseFloat(raw) || 1));
    v = Math.round(v * 4) / 4;
    setVal(v);
    numEl.value    = v;
    sliderEl.value = v;
    var svgEl = previewInner.querySelector('svg');
    if (svgEl) applyStrokeOverrides(svgEl);
  };
}

var edgeStrokeNum    = document.getElementById('cfg-edge-stroke');
var edgeStrokeSlider = document.getElementById('cfg-edge-stroke-slider');
var nodeStrokeNum    = document.getElementById('cfg-node-stroke');
var nodeStrokeSlider = document.getElementById('cfg-node-stroke-slider');

var setEdgeStroke = makeStrokeSetter(edgeStrokeNum, edgeStrokeSlider,
  function() { return cfgEdgeStroke; },
  function(v) { cfgEdgeStroke = v; }
);
var setNodeStroke = makeStrokeSetter(nodeStrokeNum, nodeStrokeSlider,
  function() { return cfgNodeStroke; },
  function(v) { cfgNodeStroke = v; }
);

edgeStrokeNum.addEventListener('input',    function() { setEdgeStroke(edgeStrokeNum.value); });
edgeStrokeSlider.addEventListener('input', function() { setEdgeStroke(edgeStrokeSlider.value); });
nodeStrokeNum.addEventListener('input',    function() { setNodeStroke(nodeStrokeNum.value); });
nodeStrokeSlider.addEventListener('input', function() { setNodeStroke(nodeStrokeSlider.value); });

// Clear every override (colors, font, padding, strokes) back to the active
// theme's defaults. setPadding / fontSelectLabel live in font-picker.js, which
// loads later but shares scope; this only runs on click, by which point they
// are defined.
function resetConfig() {
  Object.keys(cfgColors).forEach(function(k) { cfgColors[k] = ''; });
  cfgFont = '';
  if (typeof fontSelectLabel !== 'undefined' && fontSelectLabel) fontSelectLabel.textContent = 'Default';
  if (typeof setEdgeStroke === 'function') setEdgeStroke(1);
  if (typeof setNodeStroke === 'function') setNodeStroke(1);
  if (typeof setPadding === 'function') setPadding(24);
  refreshAllColorUIs();
  readConfig();
  if (typeof scheduleRender === 'function') scheduleRender(0);
  if (typeof showToast === 'function') showToast('Style reset to theme.');
}

var configResetBtn = document.getElementById('config-reset-btn');
if (configResetBtn) configResetBtn.addEventListener('click', resetConfig);

// Settings popover: use the same anchored panel grammar as Examples. It still
// brings Source forward on mobile because the config DOM lives in the left panel,
// but visually it is a topbar popover, not a separate mode.
var settingsBtn = document.getElementById('settings-btn');
var settingsCloseBtn = document.getElementById('settings-close-btn');
function positionSettingsPanel() {
  if (!configView || !settingsBtn) return;
  var rect = settingsBtn.getBoundingClientRect();
  var gutter = 12;
  var preferred = 360;
  var width = Math.min(preferred, window.innerWidth - gutter * 2);
  var left = Math.min(Math.max(gutter, rect.left), window.innerWidth - width - gutter);
  var top = rect.bottom + 8;
  var maxHeight = Math.max(260, window.innerHeight - top - gutter);
  configView.style.setProperty('--settings-left', Math.round(left) + 'px');
  configView.style.setProperty('--settings-top', Math.round(top) + 'px');
  configView.style.setProperty('--settings-width', Math.round(width) + 'px');
  configView.style.setProperty('--settings-max-height', Math.round(maxHeight) + 'px');
}

var settingsPopup = (settingsBtn && configView && typeof createPopupController === 'function')
  ? createPopupController({
      popup: configView,
      trigger: settingsBtn,
      className: 'visible',
      visibility: { manageTabStops: true, toggleTriggerClass: false },
      closeOnEscape: false,
      beforeOpen: function(meta) {
        // On mobile the source panel may be hidden (Preview view); the settings
        // DOM lives in it, so bring it forward before showing the fixed popover.
        if (typeof setMobilePanel === 'function') setMobilePanel('code');
        configView.hidden = false;
        positionSettingsPanel();
        refreshAllColorUIs();
      },
      afterOpen: function(meta) {
        settingsBtn.classList.add('active');
        settingsBtn.setAttribute('aria-pressed', 'true');
        if (meta && meta.focusFirst) {
          var first = configView.querySelector('button, input, [href], [tabindex]:not([tabindex="-1"])');
          if (first) first.focus({ preventScroll: false });
        }
      },
      afterClose: function() {
        settingsBtn.classList.remove('active');
        settingsBtn.setAttribute('aria-pressed', 'false');
        configView.hidden = true;
      },
      contains: function(target) {
        return !!(target.closest('#config-view') || target.closest('#settings-btn') || target.closest('#font-popup') || target.closest('#color-popup'));
      },
      repositionOnResize: true,
      position: positionSettingsPanel,
    })
  : { setOpen: function() {}, close: function() {}, isOpen: function() { return false; } };
function setSettingsOpen(open, meta) {
  settingsPopup.setOpen(open, meta || {});
}
if (settingsCloseBtn) settingsCloseBtn.addEventListener('click', function() { setSettingsOpen(false, { restoreFocus: true }); });
document.addEventListener('keydown', function(e) {
  if (e.key !== 'Escape' || !configView || configView.hidden) return;
  // A picker popup inside settings (font / colour) owns Escape while it is open,
  // so let it close and restore its own focus before settings reacts.
  if (document.querySelector('#font-popup:not([inert]), #color-popup:not([inert])')) return;
  setSettingsOpen(false, { restoreFocus: true });
});
setSettingsOpen(false);


var colorPopup    = document.getElementById('color-popup');
var colorNative   = document.getElementById('color-native-input');
var colorHexInput = document.getElementById('color-hex-input');
var activeColorKey = null;
var activeColorAnchor = null;

var paletteEl = document.getElementById('color-palette');
COLOR_PRESETS.forEach(function(hex) {
  var btn = document.createElement('button');
  btn.className = 'color-swatch-btn';
  btn.style.background = hex;
  btn.title = hex;
  btn.setAttribute('aria-label', 'Use ' + hex);
  btn.addEventListener('click', function() {
    setActiveColor(hex);
  });
  paletteEl.appendChild(btn);
});

var colorPopupController = createPopupController({
  popup: colorPopup,
  trigger: function() { return activeColorAnchor; },
  closePeersOnOpen: false,
  triggerEvents: false,
  visibility: { focusSelector: '#color-hex-input' },
  beforeOpen: function() {
    // Mirror of the font picker's beforeOpen: the two nested pickers share the
    // --z-popover-nested tier, so whichever opens closes the other rather than
    // letting DOM order decide which paints on top.
    if (typeof closeFontPopup === 'function') closeFontPopup(false);
    positionAnchoredPopup(colorPopup, activeColorAnchor, { width: 240, height: 400 });
  },
  afterOpen: function() {
    document.querySelectorAll('.color-edit-btn').forEach(function(btn) { btn.setAttribute('aria-expanded', btn === activeColorAnchor ? 'true' : 'false'); });
    colorHexInput.select();
  },
  afterClose: function() {
    document.querySelectorAll('.color-edit-btn').forEach(function(btn) { btn.setAttribute('aria-expanded', 'false'); });
    activeColorKey = null;
    activeColorAnchor = null;
  },
  contains: function(target) {
    return !!(target.closest('#color-popup') || target.closest('.color-edit-btn'));
  },
  repositionOnResize: true,
  position: function() { positionAnchoredPopup(colorPopup, activeColorAnchor, { width: 240, height: 400 }); },
});

function openColorPopup(key, anchorEl) {
  activeColorKey = key;
  activeColorAnchor = anchorEl;
  var labels = { bg:'Background', fg:'Foreground', accent:'Accent', line:'Line', muted:'Muted', surface:'Surface' };
  document.getElementById('color-popup-title').textContent = labels[key] || key;

  var val = cfgColors[key] || '#ffffff';
  colorHexInput.value = cfgColors[key] || '';
  if (/^#[0-9a-fA-F]{6}$/.test(val)) colorNative.value = val;

  colorPopupController.open({ focusFirst: true });
}

function setActiveColor(hex) {
  if (!activeColorKey) return;
  cfgColors[activeColorKey] = hex;
  colorHexInput.value = hex;
  if (/^#[0-9a-fA-F]{6}$/.test(hex)) colorNative.value = hex;
  updateColorUI(activeColorKey);
  readConfig();
  scheduleRender(200);
}

function closeColorPopup(restoreFocus) {
  colorPopupController.close({ restoreFocus: !!restoreFocus });
}

document.querySelectorAll('.color-edit-btn').forEach(function(btn) {
  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    var key = btn.dataset.cfg;
    if (colorPopup.classList.contains('open') && activeColorKey === key) {
      closeColorPopup(false); return;
    }
    openColorPopup(key, btn);
  });
});

document.getElementById('color-popup-close').addEventListener('click', function() { closeColorPopup(true); });

document.getElementById('color-clear-btn').addEventListener('click', function() {
  if (!activeColorKey) return;
  cfgColors[activeColorKey] = '';
  colorHexInput.value = '';
  updateColorUI(activeColorKey);
  readConfig();
  scheduleRender(200);
});

colorNative.addEventListener('input', function() {
  setActiveColor(colorNative.value);
});

colorHexInput.addEventListener('input', function() {
  var val = colorHexInput.value.trim();
  if (!val.startsWith('#')) val = '#' + val;
  if (/^#[0-9a-fA-F]{6}$/.test(val)) {
    colorNative.value = val;
    cfgColors[activeColorKey] = val;
    updateColorUI(activeColorKey);
    readConfig();
    scheduleRender(400);
  }
});


var PRESET_FONTS = [
  { name: 'Inter',           value: 'Inter',           group: 'Sans-serif' },
  { name: 'Geist',           value: 'Geist',           group: 'Sans-serif' },
  { name: 'Roboto',          value: 'Roboto',          group: 'Sans-serif' },
  { name: 'Open Sans',       value: 'Open Sans',       group: 'Sans-serif' },
  { name: 'Lato',            value: 'Lato',            group: 'Sans-serif' },
  { name: 'Poppins',         value: 'Poppins',         group: 'Sans-serif' },
  { name: 'Nunito',          value: 'Nunito',          group: 'Sans-serif' },
  { name: 'DM Sans',         value: 'DM Sans',         group: 'Sans-serif' },
  { name: 'Space Grotesk',   value: 'Space Grotesk',   group: 'Sans-serif' },
  { name: 'Arial',           value: 'Arial',           group: 'System' },
  { name: 'Georgia',         value: 'Georgia',         group: 'Serif' },
  { name: 'Merriweather',    value: 'Merriweather',    group: 'Serif' },
  { name: 'Playfair Display',value: 'Playfair Display',group: 'Serif' },
  { name: 'JetBrains Mono',  value: 'JetBrains Mono',  group: 'Monospace' },
  { name: 'Fira Code',       value: 'Fira Code',       group: 'Monospace' },
  { name: 'Source Code Pro', value: 'Source Code Pro', group: 'Monospace' },
  { name: 'Courier New',     value: 'Courier New',     group: 'Monospace' },
];

var fontPopup     = document.getElementById('font-popup');
var fontSearch    = document.getElementById('font-search');
var fontList      = document.getElementById('font-list');
var fontSelectBtn = document.getElementById('font-select-btn');
var fontSelectLabel = document.getElementById('font-select-label');

function buildFontList(query) {
  var q = (query || '').toLowerCase();
  var filtered = PRESET_FONTS.filter(function(f) {
    return !q || f.name.toLowerCase().includes(q) || f.value.toLowerCase().includes(q);
  });

  var groups = {};
  filtered.forEach(function(f) {
    if (!groups[f.group]) groups[f.group] = [];
    groups[f.group].push(f);
  });

  fontList.innerHTML = '';

  var browserFonts = [];
  try {
    document.fonts.forEach(function(ff) {
      var n = ff.family.replace(/['"]/g, '');
      if (!q || n.toLowerCase().includes(q)) browserFonts.push(n);
    });
    browserFonts = [...new Set(browserFonts)].sort();
  } catch(e) {}

  Object.keys(groups).forEach(function(group) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = group;
    fontList.appendChild(label);
    groups[group].forEach(function(f) { appendFontItem(f.name, f.value); });
  });

  if (browserFonts.length) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = 'Loaded in browser';
    fontList.appendChild(label);
    browserFonts.forEach(function(name) {
      appendFontItem(name, name);
    });
  }
}

function appendFontItem(name, value) {
  var item = document.createElement('button');
  item.type = 'button';
  item.setAttribute('role', 'option');
  item.setAttribute('aria-selected', cfgFont === value ? 'true' : 'false');
  item.className = 'font-item' + (cfgFont === value ? ' active' : '');
  var previewSpan = document.createElement('span');
  previewSpan.className = 'font-item-preview';
  previewSpan.style.fontFamily = value + ', sans-serif';
  previewSpan.textContent = 'Aa';
  var nameSpan = document.createElement('span');
  nameSpan.className = 'font-item-name';
  nameSpan.textContent = name;
  item.appendChild(previewSpan);
  item.appendChild(nameSpan);
  item.addEventListener('click', function() {
    cfgFont = value;
    fontSelectLabel.textContent = name;
    closeFontPopup();
    readConfig();
    scheduleRender(0);
    fontSelectBtn.focus();
  });
  fontList.appendChild(item);
}

var fontPopupController = createPopupController({
  popup: fontPopup,
  trigger: fontSelectBtn,
  closePeersOnOpen: false,
  visibility: { focusSelector: '#font-search' },
  beforeOpen: function() {
    // The colour picker is the one peer sharing the nested tier (both skip the
    // global peer-close so they don't dismiss the settings panel). Close it
    // here, or the two pickers contest the same z-index and DOM order decides
    // which paints on top — not the one that was opened last and holds focus.
    if (typeof closeColorPopup === 'function') closeColorPopup(false);
    buildFontList('');
    fontSearch.value = '';
    positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 });
  },
  contains: function(target) {
    return !!(target.closest('#font-popup') || target.closest('#font-select-btn'));
  },
  repositionOnResize: true,
  position: function() { positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 }); },
});

function openFontPopup() {
  fontPopupController.open({ focusFirst: true });
}

function closeFontPopup(restoreFocus) {
  fontPopupController.close({ restoreFocus: !!restoreFocus });
}

fontSearch.addEventListener('input', function() {
  buildFontList(fontSearch.value);
});

var paddingNum    = document.getElementById('cfg-padding');
var paddingSlider = document.getElementById('cfg-padding-slider');

function setPadding(val) {
  val = Math.max(0, Math.min(120, parseInt(val, 10) || 0));
  cfgPadding = val;
  paddingNum.value    = val;
  paddingSlider.value = val;
  readConfig();
  scheduleRender(200);
}

paddingNum.addEventListener('input', function() { setPadding(paddingNum.value); });
paddingSlider.addEventListener('input', function() { setPadding(paddingSlider.value); });


var currentLeftPanel = 'code';
var currentMobilePanel = 'code';

function setMobilePanel(panel) {
  currentMobilePanel = panel;
  document.body.dataset.mobilePanel = panel;
  syncModeButtons();
}

function setLeftPanelMode(panel) {
  currentLeftPanel = panel === 'config' ? 'config' : 'code';
  if (currentLeftPanel === 'code') {
    editorView.hidden = false;
    editorView.style.display = 'flex';
    configView.hidden = true;
    configView.classList.remove('visible');
    configView.setAttribute('aria-hidden', 'true');
    editorView.setAttribute('aria-hidden', 'false');
  } else {
    editorView.hidden = true;
    editorView.style.display = 'none';
    configView.hidden = false;
    configView.classList.add('visible');
    configView.setAttribute('aria-hidden', 'false');
    editorView.setAttribute('aria-hidden', 'true');
    refreshAllColorUIs();
  }
  syncModeButtons();
}

function syncModeButtons() {
  document.querySelectorAll('[data-left-panel]').forEach(function(btn) {
    var active = btn.dataset.leftPanel === currentLeftPanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  document.querySelectorAll('.mode-option[data-mobile-panel]').forEach(function(btn) {
    var active = btn.dataset.mobilePanel === currentMobilePanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
}

function activateModeButton(button, focusButton) {
  // Source/Style carry data-left-panel (+ data-mobile-panel); Preview carries
  // only data-mobile-panel. One handler drives both the desktop left-panel tab
  // and the mobile whole-view switch from the same adaptive control.
  var left = button.dataset.leftPanel;
  var mobile = button.dataset.mobilePanel || left;
  if (left) setLeftPanelMode(left);
  else if (mobile === 'code' || mobile === 'config') setLeftPanelMode(mobile);
  if (mobile) setMobilePanel(mobile);
  if (focusButton) button.focus();
}

function visibleSegmentButtons(group) {
  // offsetParent is null for display:none buttons (e.g. Preview on desktop),
  // so arrow-key nav only cycles the options actually on screen.
  return Array.prototype.slice.call(group.querySelectorAll('.mode-option')).filter(function(b) {
    return b.offsetParent !== null;
  });
}

function moveWithinSegmentedControl(button, direction) {
  var group = button.closest('[data-segmented-control]');
  if (!group) return;
  var buttons = visibleSegmentButtons(group);
  var index = buttons.indexOf(button);
  if (index < 0) return;
  var nextIndex = index;
  if (direction === 'Home') nextIndex = 0;
  else if (direction === 'End') nextIndex = buttons.length - 1;
  else nextIndex = (index + (direction === 'ArrowRight' ? 1 : -1) + buttons.length) % buttons.length;
  var next = buttons[nextIndex];
  if (next) activateModeButton(next, true);
}

document.querySelectorAll('[data-segmented-control] .mode-option').forEach(function(button) {
  button.addEventListener('click', function() { activateModeButton(button, false); });
  button.addEventListener('keydown', function(e) {
    if (!["ArrowLeft", "ArrowRight", "Home", "End"].includes(e.key)) return;
    e.preventDefault();
    moveWithinSegmentedControl(button, e.key);
  });
});

setLeftPanelMode('code');
// Mobile first-run leads with the rendered diagram and the verify bar — the
// product's proof — instead of the source pane. init.js switches back to
// Source when it restores an autosaved draft, so returning editors land
// mid-edit. Desktop keeps Source active (both panels are visible there).
setMobilePanel(
  window.matchMedia && window.matchMedia('(max-width: 760px)').matches
    ? 'preview'
    : 'code'
);


function writeClipboardText(value, success, failure, sourceBtn) {
  if (!navigator.clipboard || !navigator.clipboard.writeText) {
    setCopyFeedback(sourceBtn, 'err');
    showToast(failure || 'Copy is not supported in this browser.');
    return;
  }
  navigator.clipboard.writeText(value).then(function() {
    setCopyFeedback(sourceBtn, 'ok');
    showToast(success || 'Copied.');
    if (typeof setExportDropdownOpen === 'function') setExportDropdownOpen(false, false);
  }).catch(function() {
    setCopyFeedback(sourceBtn, 'err');
    showToast(failure || 'Copy failed.');
  });
}

function copySource() {
  writeClipboardText(editor.value, 'Source copied.', 'Copy source failed.', copySourceBtn);
}

function mermaidBodyStart(source) {
  var text = String(source || '').replace(/^---[\s\S]*?---\s*/, '');
  var lines = text.split(/\r?\n/);
  for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (!line || line.indexOf('%%') === 0) continue;
    return line;
  }
  return '';
}

function detectAgentFamily(source) {
  var first = mermaidBodyStart(source).toLowerCase();
  if (/^(graph|flowchart)\b/.test(first)) return { family: 'flowchart', narrower: 'asFlowchart' };
  if (/^statediagram(?:-v2)?\b/.test(first)) return { family: 'state', narrower: 'asState' };
  if (/^sequencediagram\b/.test(first)) return { family: 'sequence', narrower: 'asSequence' };
  if (/^timeline\b/.test(first)) return { family: 'timeline', narrower: 'asTimeline' };
  if (/^classdiagram\b/.test(first)) return { family: 'class', narrower: 'asClass' };
  if (/^erdiagram\b/.test(first)) return { family: 'er', narrower: 'asEr' };
  if (/^journey\b/.test(first)) return { family: 'journey', narrower: 'asJourney' };
  if (/^architecture\b/.test(first)) return { family: 'architecture', narrower: 'asArchitecture' };
  if (/^xychart(?:-beta)?\b/.test(first)) return { family: 'xychart', narrower: 'asXyChart' };
  if (/^pie\b/.test(first)) return { family: 'pie', narrower: 'asPie' };
  if (/^quadrantchart\b/.test(first)) return { family: 'quadrant', narrower: 'asQuadrant' };
  if (/^gantt\b/.test(first)) return { family: 'gantt', narrower: 'asGantt' };
  return { family: 'unknown', narrower: 'the matching as* helper' };
}

function buildAgentTaskPrompt() {
  var source = editor.value.trim();
  var detected = detectAgentFamily(source);
  return 'Create or edit a Mermaid diagram with Agentic Mermaid.\n\n'
    + 'Task:\n<replace with the requested diagram goal or edit>\n\n'
    + 'Context:\n<include the facts, labels, relationships, and constraints the diagram should express>\n\n'
    + 'Detected family: ' + detected.family + '\n'
    + 'Expected trace: parseMermaid → ' + detected.narrower + ' → mutate(...) → verifyMermaid → serializeMermaid\n\n'
    + 'Mermaid source (for edits; leave blank for a new diagram):\n```mermaid\n'
    + (source || '')
    + '\n```\n\n'
    + 'Environment:\n'
    + '- Do not assume this repository is checked out. Use one channel available to you: installed `agentic-mermaid/agent`, this repo\'s `./src/agent/index.ts`, the CLI (`am` or `bun run bin/am.ts`), self-hosted MCP Code Mode, or the hosted MCP at `https://agentic-mermaid.dev/mcp` (stateless streamable HTTP JSON-RPC). The website exposes no REST render API — `/mcp` speaks MCP only.\n'
    + '- If no Agentic Mermaid channel is available (local or the hosted MCP), do not fabricate verification; return the best Mermaid source and say `not verified — Agentic Mermaid unavailable` with what you tried.\n'
    + '- Library imports, when available: `parseMermaid`, `verifyMermaid`, `serializeMermaid`, `mutate`, and `as*` helpers from `agentic-mermaid/agent`.\n\n'
    + 'Workflow:\n'
    + '1. For a new diagram, author Mermaid source directly from the supplied context, then parse it with `parseMermaid`.\n'
    + '2. For an existing diagram, parse it, narrow with the matching `as*` helper (`asFlowchart`, `asSequence`, `asGantt`, etc.), and prefer the smallest `mutate(...)` operation.\n'
    + '3. Mutation ops use a `kind` discriminator (for example `{ kind: "add_edge", from, to, label }`). Discover exact ops from local types, `am capabilities --json`, or `/capabilities.json` when present.\n'
    + '4. If no typed operation fits, make the smallest source-level edit and say `source-level fallback`.\n'
    + '5. Run `verifyMermaid` on the final diagram or source. If structural warnings remain after one mechanical fix attempt, return the warnings instead of guessing.\n'
    + '6. Return mode:\n'
    + '   - In chat, return exactly these sections: Updated Mermaid, Verification, Trace.\n'
    + '   - In self-hosted MCP/Code Mode `execute(code)`, return an object with `{ source }` after verification, or `{ error, warnings }`; do not return prose from inside code.\n'
    + '7. In Updated Mermaid, include only the final Mermaid source in a ```mermaid fence. Do not return SVG, PNG, ASCII, or Unicode unless requested.\n'
    + '8. In Trace, name the channel and exact calls/ops used: `parseMermaid`, the `as*` helper, `mutate({ kind: ... })`, `verifyMermaid`, and `serializeMermaid`; for new diagrams say `no mutate`.\n\n'
    + 'Do not modify project files unless the user explicitly asked you to change files.';
}

function copyAgentTask() {
  writeClipboardText(buildAgentTaskPrompt(), 'Agent task prompt copied.', 'Copy agent task failed.', copyAgentTaskBtn);
}

function clearEditor() {
  editor.value = '';
  setEditorErrorLine(0);
  if (typeof discardEditorDraft === 'function') discardEditorDraft();
  updateLineNumbers();
  updateCursorPos();
  previewInner.innerHTML = emptyPreviewHtml();
  if (typeof setTextOutputs === 'function') setTextOutputs('', '');
  statusText.textContent = 'Ready';
  statusText.className = '';
  renderTime.textContent = '';
  if (typeof resetVerifyPanel === 'function') resetVerifyPanel('Waiting for source');
  if (typeof updateExportAvailability === 'function') updateExportAvailability();
  if (typeof markActiveExample === 'function') markActiveExample('');
  window.history.replaceState(null, '', window.location.pathname);
  showToast('Started a blank diagram.');
}

